    10→interface Section {
    11→  id: string;
    12→  title: string;
    13→  items: CheckItem[];
    14→  notes: string[];
    15→}
    16→
    17→const PRIORITY_MAP: Record<string, CheckItem["priority"]> = {
    18→  "🔴": "red",
    19→  "🟠": "orange",
    20→  "🟡": "yellow",
    21→  "🟢": "green",
    22→};
    23→
    24→const PRIORITY_LABELS: Record<CheckItem["priority"], string> = {
    25→  red: "Bloqueante",
    26→  orange: "Alta",
    27→  yellow: "Media",
    28→  green: "Nice-to-have",
    29→  none: "Hecho",
    30→};
    31→
    32→const PRIORITY_CLS: Record<CheckItem["priority"], string> = {
    33→  red: "bg-red-500/15 text-red-400 border-red-500/20",
    34→  orange: "bg-orange-500/15 text-orange-400 border-orange-500/20",
    35→  yellow: "bg-yellow-500/15 text-yellow-400 border-yellow-500/20",
    36→  green: "bg-green-500/15 text-green-400 border-green-500/20",
    37→  none: "bg-cl-accent/10 text-cl-accent border-cl-accent/20",
    38→};
    39→
    40→function detectPriority(text: string): CheckItem["priority"] {
    41→  for (const [emoji, p] of Object.entries(PRIORITY_MAP)) {
    42→    if (text.includes(emoji)) return p;
    43→  }
    44→  return "none";
    45→}
    46→
    47→function parseChecklist(md: string): Section[] {
    48→  const lines = md.split("\n");
    49→  const sections: Section[] = [];
    50→  let current: Section | null = null;
    51→
    52→  for (const line of lines) {
    53→    if (line.startsWith("## ")) {
    54→      current = { id: line.slice(3).trim().replace(/\s+/g, "-").toLowerCase(), title: line.slice(3).trim(), items: [], notes: [] };
    55→      sections.push(current);
    56→    } else if (current && /^- \[[ xX]\]/.test(line)) {
    57→      const done = /^- \[[xX]\]/.test(line);
    58→      const text = line.replace(/^- \[[ xX]\]\s*/, "").trim();
    59→      const priority = done ? "none" : detectPriority(text);
    60→      current.items.push({ done, text, priority, raw: line });
    61→    } else if (current && line.trim() && !line.startsWith("#") && !line.startsWith("|") && !line.startsWith("---")) {
    62→      current.notes.push(line);
    63→    }
    64→  }
    65→  return sections.filter((s) => s.items.length > 0);
    66→}
    67→
    68→function renderInline(text: string): string {
    69→  return text
    70→    .replace(/\*\*([^*]+)\*\*/g, "<strong>$1</strong>")
    71→    .replace(/`([^`]+)`/g, "<code class='bg-white/5 px-1 py-0.5 rounded text-cl-accent text-[11px] font-mono'>$1</code>")
    72→    .replace(/\[([^\]]+)\]\(([^)]+)\)/g, "<a href='$2' target='_blank' class='text-cl-blue underline'>$1</a>")
    73→    .replace(/🔴|🟠|🟡|🟢/g, "");
    74→}
