const ALL_TAGS = [...new Set(REPOS.flatMap(r => r.tags))].sort();

const TAG_COLORS = [
  "bg-cl-accent/10 text-cl-accent",
  "bg-purple-400/10 text-purple-300",
  "bg-blue-400/10 text-blue-300",
  "bg-yellow-400/10 text-yellow-300",
  "bg-pink-400/10 text-pink-300",
  "bg-orange-400/10 text-orange-300",
];

function tagColor(tag: string) {
  const idx = ALL_TAGS.indexOf(tag) % TAG_COLORS.length;
  return TAG_COLORS[idx];
}

export default function ResearchPage() {
  const [search, setSearch] = useState("");
  const [activeTag, setActiveTag] = useState<string | null>(null);
  const [codeOnly, setCodeOnly] = useState(false);

  const filtered = REPOS.filter(r => {
    if (codeOnly && !r.hasCode) return false;
    if (activeTag && !r.tags.includes(activeTag)) return false;
    if (search) {
      const q = search.toLowerCase();
      return r.name.toLowerCase().includes(q) || r.description.toLowerCase().includes(q) || r.tags.some(t => t.toLowerCase().includes(q));
    }
    return true;
  });

  return (
    <div className="p-6 space-y-6">
      {/* Header stats */}
      <div className="grid grid-cols-3 gap-4">
        <div className="bg-[#0d1b2e] border border-white/5 rounded-xl p-4">
          <p className="text-xs text-white/40 mb-1">Repositorios analizados</p>
          <p className="text-2xl font-bold text-white">{REPOS.length}</p>
          <p className="text-xs text-white/30 mt-1">{REPOS.filter(r => r.hasCode).length} con código local</p>
        </div>
        <div className="bg-[#0d1b2e] border border-white/5 rounded-xl p-4">
          <p className="text-xs text-white/40 mb-1">Tecnologías mapeadas</p>
          <p className="text-2xl font-bold text-white">{ALL_TAGS.length}</p>
          <p className="text-xs text-white/30 mt-1">tags de features y stack</p>
        </div>
        <div className="bg-[#0d1b2e] border border-white/5 rounded-xl p-4">
          <p className="text-xs text-white/40 mb-1">Recursos de referencia</p>
          <p className="text-2xl font-bold text-white">20+</p>
          <p className="text-xs text-white/30 mt-1">READMEs, mockups, matrices</p>
        </div>
      </div>

      {/* Research resources */}
      <div className="bg-[#0d1b2e] border border-white/5 rounded-xl p-5">
        <h3 className="text-sm font-bold text-white mb-3 flex items-center gap-2">
          <i className="ti ti-folder text-cl-accent" />
          Recursos de investigación locales
        </h3>
        <div className="grid grid-cols-2 gap-3">
          {[
            { icon: "ti-table", label: "Matrix features vs. repos", path: "docs/research/features_vs_repos.html", desc: "Comparativa completa de funcionalidades" },
            { icon: "ti-file-text", label: "READMEs de referencia", path: "docs/research/readmes/", desc: "17 READMEs analizados y anotados" },
            { icon: "ti-layout-2", label: "Mockups de referencia", path: "docs/mockups/", desc: "Flow builder, analytics, AI hub, dashboard, planes" },
            { icon: "ti-code", label: "Código fuente local", path: "attached_assets/repos/", desc: "10 repos descargados para análisis" },
          ].map(r => (
            <div key={r.path} className="flex items-start gap-3 p-3 bg-white/3 border border-white/5 rounded-lg">
              <div className="w-8 h-8 bg-cl-accent/10 rounded-lg flex items-center justify-center flex-shrink-0">
                <i className={`ti ${r.icon} text-cl-accent text-base`} />
              </div>
              <div>
                <p className="text-xs font-semibold text-white">{r.label}</p>
                <p className="text-[11px] text-white/40 mt-0.5">{r.desc}</p>
                <code className="text-[10px] text-white/30 font-mono">{r.path}</code>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Filters */}
      <div className="flex flex-wrap gap-3 items-center">
        <div className="relative flex-1 min-w-[200px]">
          <i className="ti ti-search absolute left-3 top-1/2 -translate-y-1/2 text-white/30 text-sm" />
          <input
            type="text"
            placeholder="Buscar repo, feature o tecnología..."
            value={search}
            onChange={e => setSearch(e.target.value)}
            className="w-full bg-[#0d1b2e] border border-white/10 rounded-lg pl-9 pr-3 py-2 text-sm text-white placeholder-white/30 focus:outline-none focus:border-cl-accent/50"
          />
        </div>
        <button
          onClick={() => setCodeOnly(!codeOnly)}
          className={`flex items-center gap-2 px-3 py-2 rounded-lg text-xs font-semibold border transition-all ${
            codeOnly ? "bg-cl-accent/10 border-cl-accent/30 text-cl-accent" : "bg-[#0d1b2e] border-white/10 text-white/50 hover:text-white"
          }`}
        >
          <i className="ti ti-code text-sm" />
          Solo con código local
        </button>
        {activeTag && (
          <button
            onClick={() => setActiveTag(null)}
            className="flex items-center gap-1 px-3 py-2 rounded-lg text-xs font-semibold bg-purple-400/10 border border-purple-400/20 text-purple-300"
          >
            {activeTag} <i className="ti ti-x text-sm" />
          </button>
        )}
      </div>

      {/* Tag cloud */}
      <div className="flex flex-wrap gap-2">
        {ALL_TAGS.map(tag => (
          <button
            key={tag}
            onClick={() => setActiveTag(activeTag === tag ? null : tag)}
            className={`px-2.5 py-1 rounded-full text-[11px] font-semibold transition-all border ${
              activeTag === tag
                ? "border-cl-accent/40 bg-cl-accent/15 text-cl-accent"
                : "border-white/5 bg-white/3 text-white/40 hover:text-white hover:bg-white/5"
            }`}
          >
            {tag}
          </button>
        ))}
      </div>

      {/* Repo grid */}
      <div className="grid grid-cols-2 gap-4">
        {filtered.map(repo => (
          <div key={repo.alias} className="bg-[#0d1b2e] border border-white/5 rounded-xl p-5 flex flex-col gap-3 hover:border-white/10 transition-colors">
            <div className="flex items-start justify-between gap-3">
              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-2 mb-1">
                  <span className="text-[10px] font-mono font-bold text-cl-accent bg-cl-accent/10 px-1.5 py-0.5 rounded">
                    [{repo.alias}]
                  </span>
                  {repo.hasCode && (
                    <span className="text-[10px] font-bold text-green-400 bg-green-400/10 px-1.5 py-0.5 rounded">
                      código local
                    </span>
                  )}
                </div>
                <a
                  href={repo.url}
                  target="_blank"
                  rel="noreferrer"
                  className="text-sm font-semibold text-white hover:text-cl-accent transition-colors font-mono block truncate"
                >
                  {repo.name}
                </a>
              </div>
              <a href={repo.url} target="_blank" rel="noreferrer" className="flex-shrink-0">
                <i className="ti ti-external-link text-white/20 hover:text-cl-accent transition-colors text-base" />
              </a>
            </div>
            <p className="text-xs text-white/60 leading-relaxed">{repo.description}</p>
            <div className="flex flex-wrap gap-1.5 mt-auto">
              {repo.tags.map(tag => (
                <button
                  key={tag}
                  onClick={() => setActiveTag(activeTag === tag ? null : tag)}
                  className={`text-[10px] font-semibold px-2 py-0.5 rounded-full transition-all ${tagColor(tag)} ${
                    activeTag === tag ? "ring-1 ring-cl-accent" : ""
                  }`}
                >
                  {tag}
                </button>
              ))}
            </div>
          </div>
        ))}
        {filtered.length === 0 && (
          <div className="col-span-2 text-center py-16 text-white/30">
            <i className="ti ti-microscope text-4xl mb-3 block" />
            <p className="text-sm">No hay repos que coincidan con los filtros</p>
          </div>
        )}
      </div>
    </div>
  );
}

