import { useState, useEffect, useRef } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";

/* ─── Types ─────────────────────────────────────────────── */
interface ChatbotConfig {
  id?: string;
  evolutionApiUrl?: string;
  evolutionApiKey?: string;
  evolutionInstance?: string;
  systemPrompt?: string;
  active?: boolean;
  openaiApiKey?: string;
  apiProvider?: "openrouter" | "openai";
  openrouterApiKey?: string;
  openrouterModel?: string;
  agentMode?: string;
  maxHistory?: number;
  widgetName?: string;
  widgetColor?: string;
  widgetWelcome?: string;
  widgetToken?: string;
  guardrailsJson?: string;
  businessHoursJson?: string;
}

interface ConfigResponse {
  config: ChatbotConfig | null;
  suggestedModel: string;
  plan: string;
}

interface BusinessHours {
  enabled: boolean;
  timezone: string;
  schedule: Record<string, { open: string; close: string; active: boolean }>;
  outsideHoursMessage: string;
}

interface GuardrailsConfig {
  promptInjectionShield: boolean;
  piiRedaction: boolean;
  contentFilter: boolean;
  ragHallucinationThreshold: boolean;
  bannedWords: string;
}

interface Conversation {
  id: string;
  phoneNumber: string | null;
  channel: string | null;
  lastMessageAt: string | null;
  handoffMode: boolean | null;
  leadStatus: string | null;
  leadName: string | null;
}

interface Message {
  id: string;
  role: string;
  content: string;
  createdAt: string | null;
}

interface KnowledgeItem {
  id: string;
  title: string;
  content: string;
  createdAt: string | null;
}

/* ─── Constants ─────────────────────────────────────────── */
const DAYS = [
