/* ══════════════════════════════════════════════════════════
   ONBOARDING PANEL
══════════════════════════════════════════════════════════ */
function OnboardingPanel({ status }: { status: ChatbotStatus }) {
  const steps = [
    {
      done: true,
      icon: "ti-user-check",
      label: "Cuenta creada",
      desc: "Tu cuenta está activa",
      href: null,
    },
    {
      done: status.knowledgeCount > 0,
      icon: "ti-book",
      label: "Base de conocimiento",
      desc: status.knowledgeCount > 0 ? `${status.knowledgeCount} entradas` : "Agregá info de tu negocio",
      href: "/app/agent",
    },
    {
      done: status.configured,
      icon: "ti-brand-whatsapp",
      label: "Conectar WhatsApp",
      desc: status.configured ? "Evolution API configurada" : "Configurá Evolution API",
      href: "/app/agent",
    },
    {
      done: status.active,
      icon: "ti-toggle-right",
      label: "Activar el chatbot",
      desc: status.active ? "Bot respondiendo mensajes" : "Activá el bot en configuración",
      href: "/app/agent",
    },
    {
      done: status.conversationCount > 0,
      icon: "ti-messages",
      label: "Primera conversación",
      desc: status.conversationCount > 0 ? `${status.conversationCount} conversaciones` : "Enviá un mensaje de prueba",
      href: "/app/agent",
    },
  ];

  const completed = steps.filter((s) => s.done).length;
  const allDone = completed === steps.length;
  if (allDone) return null;

  const nextStep = steps.find((s) => !s.done);

  return (
    <div className="bg-gradient-to-r from-cl-blue/10 to-cl-accent/5 border border-cl-accent/15 rounded-2xl p-5">
      <div className="flex items-center justify-between mb-4">
        <div>
          <h3 className="text-sm font-bold text-white flex items-center gap-2">
            <i className="ti ti-rocket text-cl-accent" /> Configuración inicial
          </h3>
          <p className="text-xs text-white/40 mt-0.5">{completed} de {steps.length} pasos completados</p>
        </div>
        <div className="text-right">
          <div className="text-2xl font-extrabold text-cl-accent">{Math.round((completed / steps.length) * 100)}%</div>
          <div className="w-24 h-1.5 bg-white/10 rounded-full mt-1">
            <div className="h-1.5 bg-cl-accent rounded-full transition-all" style={{ width: `${(completed / steps.length) * 100}%` }} />
          </div>
        </div>
      </div>
      <div className="grid grid-cols-5 gap-2 mb-4">
        {steps.map((step, i) => (
          <div key={i} className={`flex flex-col items-center gap-1.5 p-2 rounded-xl transition-all ${step.done ? "bg-cl-accent/10" : "bg-white/5"}`}>
            <div className={`w-7 h-7 rounded-full flex items-center justify-center text-sm ${step.done ? "bg-cl-accent text-navy" : "bg-white/10 text-white/30"}`}>
              {step.done ? <i className="ti ti-check text-xs" /> : <i className={`ti ${step.icon} text-xs`} />}
            </div>
            <span className={`text-[10px] font-semibold text-center leading-tight ${step.done ? "text-cl-accent" : "text-white/40"}`}>
              {step.label}
            </span>
          </div>
        ))}
      </div>
      {nextStep?.href && (
        <Link href={nextStep.href}
          className="inline-flex items-center gap-2 bg-cl-accent text-navy font-bold text-xs px-4 py-2 rounded-xl hover:bg-cl-accent-hover transition-all no-underline">
          <i className={`ti ${nextStep.icon}`} />
          Siguiente: {nextStep.label} →
        </Link>
      )}
    </div>
  );
}

