      setMsgs((m) => [...m, { role: "assistant", content: r.reply }]);
      if (r.model) setModel(r.model);
    } catch (err) {
      setMsgs((m) => [...m, { role: "assistant", content: `❌ Error: ${err instanceof Error ? err.message : "Error desconocido"}` }]);
