          <span className="text-xs font-bold text-white/50 uppercase tracking-wider">Chat de prueba</span>
          {model && <span className="text-[10px] text-white/30">{model}</span>}
          {msgs.length > 0 && (
            <button onClick={() => setMsgs([])} className="text-xs text-white/30 hover:text-white/60 transition-all">
              Limpiar
            </button>
          )}
        </div>
        <div className="flex-1 p-4 overflow-y-auto space-y-3 flex flex-col">
          {msgs.length === 0 && (
            <div className="text-center py-12 text-white/30">
              <i className="ti ti-robot text-4xl block mb-3 opacity-30" />
              <p className="text-sm">Mandá un mensaje para probar el chatbot con tu configuración real</p>
            </div>
          )}
          {msgs.map((m, i) => (
            <div
              key={i}
              className={`max-w-[80%] px-3 py-2.5 rounded-2xl text-sm leading-relaxed ${
                m.role === "user"
                  ? "self-end ml-auto bg-cl-accent text-navy rounded-br-sm"
                  : "self-start bg-navy-3 text-white rounded-bl-sm"
              }`}
            >
              {m.content}
            </div>
          ))}
          {loading && (
            <div className="self-start bg-navy-3 px-4 py-2.5 rounded-2xl rounded-bl-sm">
              <span className="flex gap-1">
                {[0, 1, 2].map((i) => (
                  <span key={i} className="w-1.5 h-1.5 bg-white/40 rounded-full animate-bounce" style={{ animationDelay: `${i * 0.15}s` }} />
                ))}
              </span>
            </div>
          )}
          <div ref={endRef} />
        </div>
        <div className="p-3 border-t border-white/5 flex gap-2">
          <input
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === "Enter" && !e.shiftKey && send()}
            placeholder="Escribí en español…"
            className="flex-1 bg-navy-3 border border-white/10 rounded-xl px-3 py-2.5 text-sm text-white placeholder:text-white/25 focus:outline-none focus:border-cl-accent transition-all"
          />
          <button
            onClick={send}
